mapper.select:
SELECT DEPT_CD, ORG_CD, DEPT_NM, ORD, USE_YN, CRT_BY, CRT_IP, CRT_PGM, TO_CHAR(CRT_AT, 'YYYY-MM-DD HH24:MI:SS') AS CRT_AT, UPD_BY, UPD_IP, UPD_PGM, TO_CHAR(UPD_AT, 'YYYY-MM-DD HH24:MI:SS') AS UPD_AT FROM CMS_COM_DEPT
AND (DEPT_NM LIKE '%' || #{searchKeyword} || '%' OR DEPT_CD LIKE '%' || #{searchKeyword} || '%' )
AND ORG_CD = #{orgCd}
AND USE_YN = #{useYn}
ORDER BY ORD, DEPT_CD

mapper.insert:
INSERT INTO CMS_COM_DEPT ( DEPT_CD, ORG_CD, DEPT_NM, ORD, USE_YN,
) VALUES ( #{deptCd}, #{orgCd}, #{deptNm}, #{ord}, COALESCE(#{useYn}, 'Y'),
)
